def gen(rng, size):
    n = max(1, min(size, 5000))
    arr = []
    for i in range(n):
        if i == 0 or rng.random() < 0.85:
            arr.append(rng.randint(-10000, 10000))
        else:
            arr.append(None)
    if not arr:
        arr = [0]
    if arr[0] is None:
        arr[0] = rng.randint(-10000, 10000)
    return [arr]

